"use strict";(self.webpackChunkdocusaurus_temp=self.webpackChunkdocusaurus_temp||[]).push([[632],{5599:(a,i,r)=>{r.r(i),r.d(i,{assets:()=>h,contentTitle:()=>t,default:()=>d,frontMatter:()=>s,metadata:()=>n,toc:()=>u});const n=JSON.parse('{"id":"quick-start/part2-setup","title":"2-qism: Mahsulotlar va mijozlar","description":"\\"Ushbu qo\u2018llanmaning bu bo\u2018limida siz quyidagilarni o\u2018rganasiz:","source":"@site/i18n/uz/docusaurus-plugin-content-docs/current/quick-start/part2-setup.md","sourceDirName":"quick-start","slug":"/quick-start/part2-setup","permalink":"/uz/docs/quick-start/part2-setup","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":3,"frontMatter":{"id":"part2-setup","title":"2-qism: Mahsulotlar va mijozlar","sidebar_label":"2-qism: Mahsulotlar va mijozlar","sidebar_position":3},"sidebar":"tutorialSidebar","previous":{"title":"1-qism: Sozlash","permalink":"/uz/docs/quick-start/part1-registration"},"next":{"title":"3-qism: Pullar","permalink":"/uz/docs/quick-start/part3-finance"}}');var o=r(4848),l=r(8453);const s={id:"part2-setup",title:"2-qism: Mahsulotlar va mijozlar",sidebar_label:"2-qism: Mahsulotlar va mijozlar",sidebar_position:3},t="2-qism. Mahsulotlar, mijozlar va ombor bilan ishlash",h={},u=[];function m(a){const i={h1:"h1",header:"header",p:"p",...(0,l.R)(),...a.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(i.header,{children:(0,o.jsx)(i.h1,{id:"2-qism-mahsulotlar-mijozlar-va-ombor-bilan-ishlash",children:"2-qism. Mahsulotlar, mijozlar va ombor bilan ishlash"})}),"\n",(0,o.jsx)(i.p,{children:'"Ushbu qo\u2018llanmaning bu bo\u2018limida siz quyidagilarni o\u2018rganasiz:\r\nMahsulotlar va narxlar prays listlarni qo\u2018shish\r\nMijozlar va ta\u2019minotchilarni ro\u2018yxatdan o\u2018tkazish\r\nBuyurtmalarni shakllantirish, to\u2018lovlarni kiritish va sotuvlarni yaratish\r\nAgar jarayonni soddaroq ko\u2018rsatsak, yo\u2018l quyidagicha ko\u2018rinadi:\r\nSiz ro\u2018yxatdan o\u2018tdingiz va tizimni o\u2018zingizga moslab sozladingiz \u2192 mahsulotlar ro\u2018yxatini yaratish va ombor ishini sozlash \u2192 mijozlar va ta\u2019minotchilarni yuklash \u2192 pul mablag\u2018lari qoldiqlarini tizimga kiritish \u2192 birinchi xarid va sotuv rasmiylashtirish \u2192 hisobotlar bilan ishlashni boshlash \u2192 ishga tayyorsiz!'}),"\n",(0,o.jsx)(i.p,{children:"Mahsulotlar va omborni boshqarish\r\nUshbu bosqichda biz mahsulotlarni qo\u2018shamiz va ombor boshqaruvini tashkil qilamiz. Kelajakda xatolarning oldini olish uchun har bir elementni to\u2018g\u2018ri sozlash juda muhim."}),"\n",(0,o.jsx)(i.p,{children:"Mahsulotlar va shtrix-kodlar bilan ishlash\r\nMahsulotlar faylini Excel orqali yuklash\r\nEkranning o\u2018ng yuqori burchagidagi uchta nuqtani bosing va Importni tanlang.\r\nFayl yuklash oynasi ochiladi.\r\nFaylni oynaga sudrab tashlang yoki kompyuterdan tanlang.\u2028Agar hozircha Excel formatida mahsulotlar ro\u2018yxati bo\u2018lmasa, shablonni yuklab oling."}),"\n",(0,o.jsx)(i.p,{children:"Mahsulotlar ro\u2018yxatini qo\u2018lda to\u2018ldirish\r\nMahsulotlar bo\u2018limiga o\u2018ting, Mahsulotlar yorlig\u2018iga kursorni olib boring va \u2795 tugmasini bosing. Ma\u2019lumot kiritish formasi ochiladi.\r\nMa\u2019lumotlarni to\u2018ldiring \u2014 nomi, artikuli va o\u2018lchov birligini kiriting.\u2028Agar mahsulotda shtrix-kod bo\u2018lmasa, uni shu yerning o\u2018zida yaratish mumkin. Buning uchun uchta nuqta ikonkasini bosing.\r\nBoshqa yorlig\u2018ida brendni, ta\u2019minotchini va yetib kelishi uchun zarur bo\u2018lgan vaqtni qo\u2018shishingiz mumkin.\r\nSaqlash tugmasini bosing.\r\nMASLAHAT\u2028Ombordagi zaxiralarni nazorat qilish uchun minimal qoldiq miqdorini belgilang."}),"\n",(0,o.jsx)(i.p,{children:"Xizmatlarni sozlash\r\nAgar biznesingiz mahsulotlar bilan birga xizmatlar ham ko\u2018rsatsa (masalan, yetkazib berish yoki montaj), ularni tizimga qo\u2018shing. Bu nafaqat mahsulot operatsiyalarini, balki xizmatlarni ham hisobga olish imkonini beradi."}),"\n",(0,o.jsx)(i.p,{children:"Prays listlar\r\nNarxlar ro\u2018yxatini keyinroq yaratish va sozlash mumkin. Ular turli mijozlar yoki savdo shartlari uchun turli narxlarni avtomatik hisobga olishga yordam beradi."}),"\n",(0,o.jsx)(i.p,{children:"Shtrix-kodlarni chop etish\r\nMahsulotlar uchun shtrix-kodlarni chop etishni sozlang \u2014 bu inventarizatsiyani soddalashtiradi va kassada ishlashni tezlashtiradi. Qanday qilishni bilish uchun tegishli yo\u2018riqnomadan foydalaning."}),"\n",(0,o.jsx)(i.p,{children:"Ombor bilan ishlashni boshlash\r\nTizim bilan ishni boshlaganda, ombordagi qoldiqlar to\u2018g\u2018ri kiritilganini tekshirish muhim. Korrektirovka yordamida barcha ma\u2019lumotlarni tartibga keltirish mumkin.\r\nKorrektirovka qo\u2018shish\r\nOmbor bo\u2018limiga o\u2018ting, Korrektirovkalar ustiga kursorni olib boring va \u2795 tugmasini bosing. Ma\u2019lumot kiritish formasi ochiladi.\r\nFormani to\u2018ldiring:\r\nSana va korrektirovka raqamini, hujjat valyutasini ko\u2018rsating\r\nKorrektirovka qilinadigan omborni tanlang\r\nMahsulotlarni ochiladigan ro\u2018yxat yoki filtr orqali qo\u2018shing.\u2028Mahsulotlarni filtr oynasi orqali tanlash yoki Excel orqali Import qilish mumkin\r\nSaqlash tugmasini bosing.\r\nKo\u2018chirishlar yorlig\u2018ida omborlar o\u2018rtasida mahsulotlarni ko\u2018chirishni boshqarishingiz mumkin."}),"\n",(0,o.jsx)(i.p,{children:"Mijozlar va ta\u2019minotchilar\r\nEndi kontragentlarni \u2014 siz ishlaydigan kompaniyalarni qo\u2018shish vaqti keldi."}),"\n",(0,o.jsx)(i.p,{children:"Mijozlarni qo\u2018shish\r\nAgar mijozlar ro\u2018yxatini Excel\u2019da tayyorlagan bo\u2018lsangiz, Mijozlar \u2192 Mijozlar bo\u2018limiga o\u2018ting va ekranning o\u2018ng yuqori burchagidagi uchta nuqtani bosing. Fayl yuklash oynasi ochiladi.\r\nExcel faylini tizimga yuklang.\r\nQo\u2018lda qo\u2018shish uchun:\r\nMijozlar moduliga o\u2018ting, Mijozlar bo\u2018limiga kursorni olib boring va \u2795 tugmasini bosing.\r\nTashkilotning asosiy ma\u2019lumotlarini kiriting \u2014 nomi, hududi, telefon raqami\r\nAloqa raqamlar va rekvizitlarni qo\u2018shing\r\nBoshqa yorlig\u2018ida tartib raqamini belgilang: raqam qanchalik katta bo\u2018lsa, mijoz ro\u2018yxatda shunchalik yuqorida bo\u2018ladi. Shu yerda prays listlarni ham biriktirish mumkin\r\nMa\u2019lumotlar egasini ko\u2018rsating \u2014 bu kirishni boshqarish va ma\u2019lumotlarni himoyalashga yordam beradi\r\nSaqlash tugmasini bosing\r\nMASLAHAT\u2028Yetkazib berish marshrutlarini sozlash logistika jarayonlarini optimallashtiradi, transport xarajatlarini kamaytiradi va mijozlarga xizmat ko\u2018rsatishni yaxshilaydi. Ularni Marshrutlar bo\u2018limida sozlash mumkin."}),"\n",(0,o.jsx)(i.p,{children:"Ta\u2019minotchilarni qo\u2018shish\r\nTa\u2019minotchilar ro\u2018yxatini tizimga qo\u2018shish uchun Mijozlar bo\u2018limiga o\u2018ting va Excel faylini import qiling. Ma\u2019lumotlar avtomatik tarzda Ta\u2019minotchilar bo\u2018limiga o\u2018tkaziladi.\r\nQo\u2018lda qo\u2018shish uchun:\r\nTa\u2019minotchilar bo\u2018limida \u2795 tugmasini bosing \u2014 yangi ta\u2019minotchi qo\u2018shish oynasi ochiladi\r\nTashkilotning asosiy ma\u2019lumotlarini kiriting \u2014 nomi, hududu, telefon raqami\r\nRasm, aloqa raqamlar va rekvizitlarni qo\u2018shing\r\nBoshqa yorlig\u2018ida tartib raqamini belgilang va kerak bo\u2018lsa prays listlarni qo\u2018shing\r\nAxborotga kirishni nazorat qilish uchun ma\u2019lumotlar egasini belgilang\r\nSaqlash tugmasini bosing"}),"\n",(0,o.jsx)(i.p,{children:"Qarzdorlar va kreditorlar bilan ishlash\r\nTizimda debitor va kreditor qarzlarni nazorat qilish uchun qulay bo\u2018limlar mavjud bo\u2018lib, ular moliyaviy holatingizni doim kuzatib borish imkonini beradi.\r\nMijozlar \u2192 Qarzdorlar\u2028Bu yerda mijozlar bo\u2018yicha umumiy qarzdorlik va qarz summalarini ko\u2018rishingiz mumkin. Ma\u2019lumotlarni qarz miqdori yoki oxirgi to\u2018lov sanasi bo\u2018yicha tartiblash mumkin.\r\nTa\u2019minotchilar \u2192 Kreditorlar\u2028Bu bo\u2018limda kompaniyangiz kimga va qancha qarzdor ekanini ko\u2018rasiz, shuningdek to\u2018lov muddatlarini belgilash va to\u2018lovlarni qo\u2018shish mumkin."}),"\n",(0,o.jsx)(i.p,{children:"Xaridlar va savdolarni boshqarish\r\nXaridlar va ta\u2019minotchilarga buyurtmalar\r\nXaridlar moduli ta\u2019minotchilardan mahsulot sotib olishning barcha bosqichlarini \u2014 buyurtmadan, mahsulot omborga kelguncha bo\u2018lgan jarayonni kuzatishga yordam beradi.\r\nModul ichida quyidagilar mavjud:\r\nXaridlar \u2014 qabul qilingan mahsulotlarni qayd etish uchun\r\nTa\u2019minotchilarga buyurtmalar \u2014 oldindan buyurtmalarni rasmiylashtirish uchun\r\nTa\u2019minotchilarga qaytarishlar \u2014 mahsulotning bir qismini qaytarish zarur bo\u2018lsa\r\nXarid shartnomalari \u2014 uzoq muddatli kelishuvlar bo\u2018yicha hisob yuritish uchun"}),"\n",(0,o.jsx)(i.p,{children:"Mahsulotga buyurtma berish\r\nTizimni tez tushunish uchun sxema:\r\nTa\u2019minotchiga buyurtma \u2192 mahsulot darhol keladimi?\r\nHa \u2192 bu oddiy buyurtma \u2192 xarid yaratish\r\nYo\u2018q \u2192 bu import \u2192 ta\u2019minotchiga buyurtma yaratish \u2192 mahsulot kelgach xaridga aylantirish\r\nMasalan, siz mahsulotni bugun buyurtma qildingiz, lekin u bir oyda keladi. Avval ta\u2019minotchiga buyurtma yarating va kutilayotgan yetkazib berish sanasini belgilang. Mahsulot kelgach, uni xaridga aylantirib, ombor qoldig\u2018iga qo\u2018shasiz.\r\nAgar mahsulot shu kunning o\u2018zida keladigan bo\u2018lsa, darhol xaridni rasmiylashtirish mumkin."}),"\n",(0,o.jsx)(i.p,{children:"Xaridni rasmiylashtirish\r\nXaridlar bo\u2018limiga o\u2018ting va \u2795 tugmasini bosing\r\nRo\u2018yxatdan ta\u2019minotchini tanlang\r\nSana, xarid raqami va agar mavjud bo\u2018lsa shartnomani qo\u2018shing\r\nMas\u2019ul xodimni va xarid valyutasini belgilang\r\nOmborni tanlang va mahsulotlarni miqdori bilan qo\u2018shing\r\nNarxni kiriting \u2014 oxirgi xarid narxini qo\u2018llash yoki narxlar ro\u2018yxatidan tanlash mumkin\r\nTo\u2018lov muddatini belgilang, izoh qo\u2018shing yoki fayllarni biriktiring\r\nSaqlash tugmasini bosing \u2014 xarid Qabul qilindi statusi bilan ro\u2018yxatda paydo bo\u2018ladi\r\nOGOHLANTIRISH\u2028Har doim real xarid narxini ko\u2018rsating. Bu moliyaviy holatni to\u2018g\u2018ri baholash va biznes uchun to\u2018g\u2018ri qarorlar qabul qilishga yordam beradi."}),"\n",(0,o.jsx)(i.p,{children:"Ta\u2019minotchiga buyurtma rasmiylashtirish\r\nXaridlar modulida Ta\u2019minotchilarga buyurtmalar yorlig\u2018iga o\u2018ting\r\n\u2795 tugmasini bosing\r\nTa\u2019minotchini tanlang va mahsulotlarni miqdori bilan qo\u2018shing\r\nKutilayotgan yetkazib berish sanasini belgilang\r\nSaqlash tugmasini bosing \u2014 buyurtma Qabul qilindi statusi bilan paydo bo\u2018ladi\r\nMA\u2019LUMOT\u2028Ta\u2019minotchiga buyurtma ombor qoldiqlariga ta\u2019sir qilmaydi \u2014 u faqat xarid niyatini qayd etadi va kelayotgan yetkazib berishlarni unutmaslikka yordam beradi."}),"\n",(0,o.jsx)(i.p,{children:'Savdolar\r\nBuyurtma yaratish va sotuvni rasmiylashtirish\r\nTizimda savdoni rasmiylashtirishning ikki usuli mavjud: Buyurtmalar orqali yoki to\u2018g\u2018ridan-to\u2018g\u2018ri Sotuv orqali. Quyida mahsulotni sotuvi misoli keltiriladi.\r\nSotuvlar bo\u2018limida Sotuvlarni oching va \u2795 tugmasini bosing\r\nRo\u2018yxatdan mijozni tanlang\r\nMahsulotlarni qo\u2018shing va har biri uchun kerakli miqdorni ko\u2018rsating\r\nAgar kerak bo\u2018lsa, narxni tahrirlang \u2014 \u2795 va \u2796 tugmalari orqali chegirma yoki ustama belgilang\r\nSotuv uchun mas\u2019ul shaxsni va yetkazib beruvchi haqidagi ma\u2019lumotlarni kiriting\r\nAgar mijoz hali to\u2018lov qilmagan bo\u2018lsa, to\u2018lov usuli va muddatini belgilang\r\nSaqlash tugmasini bosing \u2014 sotuv Jo\u2018natishga tayyor statusi bilan paydo bo\u2018ladi\r\nTo\u2018lov kelib tushgach, buyurtmani yakunlash uchun Yakunlash tugmasini bosing\r\nMA\u2019LUMOT\u2028To\u2018lov qo\u2018shish uchun umumiy ro\u2018yxatda jo\u2018natmani tahrirlash maqsadida qalamcha belgisini bosing."'})]})}function d(a={}){const{wrapper:i}={...(0,l.R)(),...a.components};return i?(0,o.jsx)(i,{...a,children:(0,o.jsx)(m,{...a})}):m(a)}},8453:(a,i,r)=>{r.d(i,{R:()=>s,x:()=>t});var n=r(6540);const o={},l=n.createContext(o);function s(a){const i=n.useContext(l);return n.useMemo(function(){return"function"==typeof a?a(i):{...i,...a}},[i,a])}function t(a){let i;return i=a.disableParentContext?"function"==typeof a.components?a.components(o):a.components||o:s(a.components),n.createElement(l.Provider,{value:i},a.children)}}}]);